#ifndef _KERNEL_H_
#define _KERNEL_H_

kernel void BFS_1(Node* g_graph_nodes, int* g_graph_edges, char* g_graph_mask, char* g_updating_graph_mask, char* g_graph_visited, int* g_cost, int no_of_nodes)
{
    int tid = get_global_id(0);
    if(tid < no_of_nodes && g_graph_mask[tid])
    {
        g_graph_mask[tid] = 0;
        for(int i = g_graph_nodes[tid].starting; i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting); i++)
        {
            int id = g_graph_edges[i];
            if(!g_graph_visited[id])
            {
                g_cost[id] = g_cost[tid] + 1;
                g_updating_graph_mask[id] = 1;
            }
        }
    }
}

kernel void BFS_2(char* g_graph_mask, char* g_updating_graph_mask, char* g_graph_visited, char* g_over, int no_of_nodes)
{
    int tid = get_global_id(0);
    if(tid < no_of_nodes && g_updating_graph_mask[tid])
    {
        g_graph_mask[tid] = 1;
        g_graph_visited[tid] = 1;
        *g_over = 1;
        g_updating_graph_mask[tid] = 0;
    }
}

#endif
